import torch
from sentence_transformers import SentenceTransformer
import numpy as np

device = "cuda" if torch.cuda.is_available() else "cpu"
# Instantiate once per process — multiple instances OOM on GPU
model = SentenceTransformer("BAAI/bge-large-en-v1.5", device=device)

def get_local_embedding(text: str) -> np.ndarray:
    return model.encode(text, normalize_embeddings=True)

def get_local_embeddings_batch(texts: list[str], batch_size: int = 32) -> np.ndarray:
    return model.encode(
        texts,
        batch_size=batch_size,
        show_progress_bar=True,
        convert_to_numpy=True,
        normalize_embeddings=True,
    )

# BGE-M3: dense + sparse for hybrid search
from FlagEmbedding import BGEM3FlagModel
bgem3 = BGEM3FlagModel("BAAI/bge-m3", use_fp16=True)

def get_bgem3_dense(texts: list[str]) -> np.ndarray:
    return bgem3.encode(texts, return_dense=True)["dense_vecs"]

def get_bgem3_sparse(texts: list[str]) -> list[dict]:
    return bgem3.encode(texts, return_sparse=True)["lexical_weights"]

import ollama

def get_ollama_embedding(text: str, model: str = "nomic-embed-text") -> list[float]:
    response = ollama.embeddings(model=model, prompt=text)
    return response["embedding"]

# Ollama has no native batch endpoint — sequential loop is the only option
def get_ollama_embeddings_batch(texts: list[str], model: str = "nomic-embed-text") -> list[list[float]]:
    return [
        ollama.embeddings(model=model, prompt=t)["embedding"]
        for t in texts
    ]
